from crewai import Agent, Task, Crew
from vex_sdk import VexClient

vex = VexClient(api_key='your-vex-key')

def vex_callback(task, context):
    result = vex.check('education-pii-policy', {
        'input': task.input,
        'output': context.get('output', ''),
        'domain': 'education'
    })
    if not result['pass']:
        raise ValueError(f'Compliance failure: {result["reason"]}')
    return context

# Example task with Vex
def create_tutor_task():
    return Task(
        description='Generate personalized math lesson for student ID 12345',
        agent=tutor_agent,
        callback=vex_callback
    )

