# Custom loop detection
@monitor.hook('delegation')
def check_delegation(source, target, payload):
    if monitor.detect_loop(source, target):
        return {'block': True, 'reason': 'Delegation loop detected'}
    pii_check = monitor.scan_pii(payload)
    return {'pass': not pii_check}
